def assess(record: dict) -> str:
    required = {'case_id', 'known_steps', 'branch_count', 'tool_choice_uncertain', 'baseline_success', 'agent_success'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (not record["known_steps"] or record["agent_success"] > record["baseline_success"])) else "KEEP_DETERMINISTIC_WORKFLOW"

valid = {'agent_success': 0.9, 'baseline_success': 0.96, 'branch_count': 2, 'case_id': 'CASO-AYA-049-1A', 'known_steps': True, 'tool_choice_uncertain': False}
invalid = {'agent_success': 0.9, 'baseline_success': 0.96, 'branch_count': 2, 'case_id': 'CASO-AYA-049-1A', 'known_steps': False, 'tool_choice_uncertain': False}
incomplete = {**valid}
incomplete.pop('agent_success', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

